     <div class="grid g2">
       <div class="card">
         <div class="label mb20">The 21-Step Scale · Adams Zone System · Hover / Click to copy</div>
         <div class="scale" id="greyScale"></div>
         <div class="flex between mt20" style="font-family:var(--mono);font-size:11px;color:var(--muted)">
           <span>L*=0</span><span>L*=25</span><span>L*=50</span><span>L*=75</span><span>L*=100</span>
         </div>
       </div>
       <div class="inspector">
         <div class="swatch" id="inspSwatch" style="background:#808080"></div>
         <div class="kv"><span class="k">Name</span><span id="inspName">Gray 50</span></div>
         <div class="kv"><span class="k">Hex</span><span class="mono" id="inspHex">#808080</span></div>
         <div class="kv"><span class="k">sRGB</span><span class="mono" id="inspRgb">128,128,128</span></div>
