         <div class="kv"><span class="k">CIELAB L*</span><span class="mono" id="inspLab">53.6</span></div>
         <div class="kv"><span class="k">Adams Zone</span><span class="mono">V</span></div>
         <div class="kv"><span class="k">Reflectance</span><span class="mono">18%</span></div>
