       <div class="simul" style="gap:30px">
         <div style="flex:1">
           <div style="font-family:var(--mono);font-size:11px;color:var(--muted);margin-bottom:8px">LINEAR sRGB (wrong)</div>
           <div class="scale-row neutral" style="background:linear-gradient(90deg,#000,#1a1a1a,#333,#4d4d4d,#666,#808080,#999,#b3b3b3,#ccc,#e6e6e6,#fff)"></div>
         </div>
