     </div>

     <div class="card mt40">
       <div class="label mb20">Grey Has Temperature · Warm → Neutral → Cool</div>
       <div class="grid g3">
         <div class="temp-chip"><span class="sw" style="background:#7D7873"></span><div><div style="font-weight:700">Warm Grey</div><div class="faint mono" style="font-size:11px">#7D7873 · R+Y bias</div></div></div>
         <div class="temp-chip"><span class="sw" style="background:#808080"></span><div><div style="font-weight:700">Neutral Grey</div><div class="faint mono" style="font-size:11px">#808080 · True achromatic</div></div></div>
         <div class="temp-chip"><span class="sw" style="background:#73787D"></span><div><div style="font-weight:700">Cool Grey</div><div class="faint mono" style="font-size:11px">#73787D · Blue bias</div></div></div>
       </div>
